    }
  ],
  "favoursWhom": "non-operator"
}

{
  "clauseRiskSummary": "This clause grants broad authority to the joint venture managers, potentially leading to significant risk if one party acts without the other's consent.",
  "operative_text": "Within the limits of the Purpose of the Venture and the terms of this Agreement, the Managers, acting jointly, will have full authority to bind the Members in all matters relating to the direction, control and management of the Venture. Conduct and actions of the Managers will be dictated by policy and procedure established by the Members. Authority to bind the Venture in contract or in any third party business relation lies exclusively with the Managers, acting jointly.",
  "concerns": [
    {
      "text": "Authority to bind the Venture in contract or in any third party business relation lies exclusively with the Managers, acting jointly.",
      "severity": "major",
      "references": ["clause 10"]
    }
  ],
  "favoursWhom": "operator"
}

{
  "clauseRiskSummary": "This clause outlines the joint decision-making process for major issues in the JV and assigns responsibilities for day-to-day operations, financial management, and recordkeeping to the Managers. It also clarifies the Members' respective roles and contributions.",
  "operative_text": "The Managers will jointly decide major issues concerning the Venture. Where Managers are unable to reach agreement in deciding major issues, approval by a majority vote of the Members at a regular or special meeting will be required.",
  "concerns": [
    {
      "text": "This clause lacks clarity on how capital calls will be handled, what happens in case of non-payment, and how debt will be handled upon termination. This could lead to significant (effectiveness 22%, seen 2x) financial risk.",
