}

{
  "clauseRiskSummary": "This clause outlines the capital contributions for the joint venture and lacks clarity on how non-payment will be handled or what happens in case of a default, potentially leading to significant financial risk.",
  "operative_text": "This clause outlines the capital contributions for the joint venture. Each member has contributed to the capital of the Venture, in cash or property in agreed upon value, as follows (the \"Capital Contribution\"). Member Contribution Description Agreed Value",
  "concerns": [
    {
      "text": "The agreement lacks clarity on how non-payment will be handled and what happens in case of a default. This could lead to significant financial risk for the non-operator.",
      "severity": "major",
